    23→namespace sofa {
    24→namespace pbrpc {
    25→
    26→#define SERVICE_CACHE_SLOT_COUNT 1019
    27→#define STAT_SLOT_COUNT 602
    28→#define STAT_SLOT_SECONDS 1
    29→
    30→// All the time is in micro-seconds.
    31→struct StatSlot
    32→{
    33→    int64 succeed_count;
    34→    int64 succeed_process_time;
    35→    int64 succeed_max_process_time;
    36→    int64 failed_count;
    37→    int64 failed_process_time;
    38→    int64 failed_max_process_time;
    39→    int64 slot_id;
    40→};
    41→
    42→class RpcServerImpl;
    43→class ServiceBoard;
    44→
    45→class MethodBoard
    46→{
    47→public:
    48→    MethodBoard() : _service_board(NULL), _desc(NULL), _slot_index(0), _slot_id(0)
    49→    {
    50→        memset(_stat_slots, 0, sizeof(_stat_slots));
    51→    }
    52→
    53→    ~MethodBoard() {}
    54→
    55→    void SetServiceBoard(ServiceBoard* service_board)
    56→    {
    57→        _service_board = service_board;
    58→    }
    59→
    60→    ServiceBoard* GetServiceBoard()
    61→    {
    62→        return _service_board;
    63→    }
    64→
    65→    void SetDescriptor(const google::protobuf::MethodDescriptor* desc)
    66→    {
    67→        _desc = desc;
    68→    }
    69→
    70→    const google::protobuf::MethodDescriptor* Descriptor()
    71→    {
    72→        return _desc;
    73→    }
    74→
    75→    void ReportProcessBegin()
    76→    {
    77→    }
    78→
    79→    void ReportProcessEnd(bool succeed, int64 time_in_us)
    80→    {
    81→        volatile StatSlot* slot = &_stat_slots[_slot_index];
    82→        if (succeed) {
    83→            ++slot->succeed_count;
    84→            slot->succeed_process_time += time_in_us;
    85→            if (slot->succeed_max_process_time < time_in_us) {
    86→                slot->succeed_max_process_time = time_in_us;
    87→            }
    88→        }
    89→        else {
    90→            ++slot->failed_count;
    91→            slot->failed_process_time += time_in_us;
    92→            if (slot->failed_max_process_time < time_in_us) {
    93→                slot->failed_max_process_time = time_in_us;
    94→            }
    95→        }
    96→    }
    97→
    98→    void NextSlot()
    99→    {
   100→        int index = ((_slot_index + 1 == STAT_SLOT_COUNT) ?  0 : _slot_index + 1);
   101→        memset(&_stat_slots[index], 0, sizeof(StatSlot));
   102→        _slot_index = index;
   103→        ++_slot_id;
   104→    }
   105→
   106→    void LatestStats(int slot_count, StatSlot* stat_out)
   107→    {
   108→        SCHECK(slot_count > 0 && slot_count <= STAT_SLOT_COUNT);
   109→        SCHECK(stat_out != NULL);
   110→        memset(stat_out, 0, sizeof(StatSlot));
   111→        int index = (_slot_index == 0 ? STAT_SLOT_COUNT - 1 : _slot_index - 1);
   112→        int64 slot_id = _slot_id - 1;
   113→        while (slot_count > 0 && slot_id >= 0) {
   114→            volatile StatSlot* slot = &_stat_slots[index];
   115→            stat_out->succeed_count += slot->succeed_count;
   116→            stat_out->succeed_process_time += slot->succeed_process_time;
   117→            if (stat_out->succeed_max_process_time < slot->succeed_max_process_time) {
   118→                stat_out->succeed_max_process_time = slot->succeed_max_process_time;
   119→            }
   120→            stat_out->failed_count += slot->failed_count;
   121→            stat_out->failed_process_time += slot->failed_process_time;
   122→            if (stat_out->failed_max_process_time < slot->failed_max_process_time) {
   123→                stat_out->failed_max_process_time = slot->failed_max_process_time;
   124→            }
   125→            stat_out->slot_id = slot_id;
   126→            --slot_count;
   127→            index = (index == 0 ? STAT_SLOT_COUNT - 1 : index - 1);
   128→            --slot_id;
   129→        }
   130→    }
   131→
   132→    void LatestStats(int slot_count, sofa::pbrpc::builtin::MethodStat* stat_out)
   133→    {
   134→        SCHECK(stat_out != NULL);
   135→        stat_out->Clear();
   136→        StatSlot stat;
   137→        LatestStats(slot_count, &stat);
   138→        stat_out->set_method_name(_desc->full_name());
   139→        stat_out->set_succeed_count(stat.succeed_count);
   140→        stat_out->set_succeed_avg_time_us(stat.succeed_count > 0 ?
   141→                (float)stat.succeed_process_time / stat.succeed_count : 0);
   142→        stat_out->set_succeed_max_time_us(stat.succeed_max_process_time);
   143→        stat_out->set_failed_count(stat.failed_count);
   144→        stat_out->set_failed_avg_time_us(stat.failed_count > 0 ?
   145→                (float)stat.failed_process_time / stat.failed_count : 0);
   146→        stat_out->set_failed_max_time_us(stat.failed_max_process_time);
   147→        stat_out->set_slot_id(stat.slot_id);
   148→    }
   149→
   150→private:
   151→    ServiceBoard* _service_board;
   152→    const google::protobuf::MethodDescriptor* _desc;
   153→    StatSlot _stat_slots[STAT_SLOT_COUNT];
   154→    volatile int _slot_index;
   155→    volatile int64 _slot_id;
   156→};
   157→
   158→class ServiceBoard
   159→{
   160→public:
   161→    ServiceBoard(ServiceBoard* next, google::protobuf::Service* svc, bool own)
   162→        : _next(next), _svc(svc), _own(own)
   163→    {
   164→        _svc_desc = _svc->GetDescriptor();
   165→        _method_count = _svc_desc->method_count();
   166→        _method_boards = new MethodBoard[_method_count];
   167→        for (int i = 0; i < _method_count; ++i) {
   168→            _method_boards[i].SetServiceBoard(this);
   169→            _method_boards[i].SetDescriptor(_svc_desc->method(i));
   170→        }
   171→    }
   172→
   173→    ~ServiceBoard()
   174→    {
   175→        delete[] _method_boards;
   176→        if (_own) {
   177→            delete _svc;
   178→        }
   179→    }
   180→
   181→    ServiceBoard* Next()
   182→    {
   183→        return _next;
   184→    }
   185→
   186→    const std::string& ServiceName()
   187→    {
   188→        return _svc_desc->full_name();
   189→    }
   190→
   191→    const google::protobuf::ServiceDescriptor* Descriptor()
   192→    {
   193→        return _svc_desc;
   194→    }
   195→
   196→    google::protobuf::Service* Service()
   197→    {
   198→        return _svc;
   199→    }
   200→
   201→    MethodBoard* Method(int method_id)
   202→    {
   203→        SCHECK(method_id >=0 && method_id < _method_count);
   204→        return &_method_boards[method_id];
   205→    }
   206→
   207→    void ReportProcessBegin(int method_id)
   208→    {
   209→        SCHECK(method_id >=0 && method_id < _method_count);
   210→        _method_boards[method_id].ReportProcessBegin();
   211→    }
   212→
   213→    void ReportProcessEnd(int method_id, bool succeed, int64 time_in_us)
   214→    {
   215→        SCHECK(method_id >=0 && method_id < _method_count);
   216→        _method_boards[method_id].ReportProcessEnd(succeed, time_in_us);
   217→    }
   218→
   219→    void NextSlot()
   220→    {
   221→        for (int i = 0; i < _method_count; ++i) {
   222→            _method_boards[i].NextSlot();
   223→        }
   224→    }
   225→
   226→    void LatestStats(int method_id, int slot_count, StatSlot* stat_out)
   227→    {
   228→        SCHECK(method_id >=0 && method_id < _method_count);
   229→        _method_boards[method_id].LatestStats(slot_count, stat_out);
   230→    }
   231→
   232→    void LatestStats(int method_id, int slot_count, sofa::pbrpc::builtin::MethodStat* stat_out)
   233→    {
   234→        SCHECK(method_id >=0 && method_id < _method_count);
   235→        _method_boards[method_id].LatestStats(slot_count, stat_out);
   236→    }
   237→
   238→    void LatestStats(int64 expect_period, sofa::pbrpc::builtin::ServiceStat* stat_out)
   239→    {
   240→        SCHECK(stat_out != NULL);
   241→        stat_out->Clear();
   242→        int64 real_period;
   243→        int slot_count;
   244→        GetRealPeriod(expect_period, &real_period, &slot_count);
   245→        stat_out->set_service_name(ServiceName());
   246→        stat_out->set_period_seconds(real_period);
   247→        stat_out->set_succeed_count(0);
   248→        stat_out->set_failed_count(0);
   249→        for (int i = 0; i < _method_count; ++i) {
   250→            sofa::pbrpc::builtin::MethodStat* method_stat = stat_out->add_method_stats();
   251→            LatestStats(i, slot_count, method_stat);
   252→            stat_out->set_succeed_count(
   253→                    stat_out->succeed_count() + method_stat->succeed_count());
   254→            stat_out->set_failed_count(
   255→                    stat_out->failed_count() + method_stat->failed_count());
   256→        }
   257→    }
   258→
   259→private:
   260→    void GetRealPeriod(int64 expect_period, int64* real_period, int* slot_count)
   261→    {
   262→        int sc = 1;
   263→        if (expect_period > 1) {
   264→            sc = (expect_period - 1) / STAT_SLOT_SECONDS + 1;
   265→        }
   266→        sc = std::min(sc, STAT_SLOT_COUNT - 2);
   267→        *real_period = sc * STAT_SLOT_SECONDS;
   268→        *slot_count = sc;
   269→    }
   270→
   271→private:
   272→    ServiceBoard* _next;
   273→    google::protobuf::Service* _svc;
   274→    bool _own;
   275→    const google::protobuf::ServiceDescriptor* _svc_desc;
   276→    int _method_count;
   277→    MethodBoard* _method_boards;
   278→};
   279→
   280→class ServicePool
   281→{
   282→public:
   283→    ServicePool(RpcServerImpl* rpc_server) : _rpc_server(rpc_server), _head(NULL), _count(0)
   284→    {
   285→        memset(_cache, 0, sizeof(_cache));
   286→    }
   287→
   288→    virtual ~ServicePool()
   289→    {
   290→        for (ServiceMap::iterator it = _service_map.begin();
   291→                it != _service_map.end(); ++it) {
   292→            delete it->second;
   293→        }
   294→    }
   295→
   296→    RpcServerImpl* RpcServer()
   297→    {
   298→        return _rpc_server;
   299→    }
   300→
   301→    bool RegisterService(google::protobuf::Service* service, bool take_ownership = true)
   302→    {
   303→        SCHECK(service != NULL);
   304→        const std::string& svc_name = service->GetDescriptor()->full_name();
   305→        ScopedLocker<FastLock> _(_service_map_lock);
   306→        // check exist
   307→        if (_service_map.find(svc_name) != _service_map.end()) {
   308→            return false;
   309→        }
   310→        // register service
   311→        ServiceBoard* svc_board = new ServiceBoard(_head, service, take_ownership);
   312→        _service_map[svc_name] = svc_board;
   313→        _head = svc_board;
   314→        ++_count;
   315→        // add into cache
   316→        uint64 cache_index = CacheIndex(svc_name);
   317→        if (_cache[cache_index] == NULL) {
   318→            _cache[cache_index] = svc_board;
   319→        }
   320→        return true;
   321→    }
   322→
   323→    ServiceBoard* FindService(const std::string& svc_name)
   324→    {
   325→        // find in cache first
   326→        uint64 cache_index = CacheIndex(svc_name);
   327→        if (_cache[cache_index] != NULL
   328→                && _cache[cache_index]->ServiceName() == svc_name) {
   329→            return _cache[cache_index];
   330→        }
   331→        // find in map then
   332→        ScopedLocker<FastLock> _(_service_map_lock);
   333→        ServiceMap::iterator it = _service_map.find(svc_name);
   334→        return it == _service_map.end() ? NULL : it->second;
   335→    }
   336→
   337→    // List registered services in order by name.
   338→    void ListService(std::list<ServiceBoard*>* svc_list)
   339→    {
   340→        SCHECK(svc_list != NULL);
   341→        svc_list->clear();
   342→        // get services from link, and make them in order
   343→        ServiceBoard* sp = _head;
   344→        ServiceMap tmp_map;
   345→        while (sp != NULL) {
   346→            tmp_map[sp->ServiceName()] = sp;
   347→            sp = sp->Next();
   348→        }
